#include <bits/stdc++.h>
#define int long long
using namespace std;
const int mod = 19260817;
int exgcd (int a, int b, int &x, int &y) {
	if (b == 0) {
		x = 1;
		y = 0;
		return a;
	}
	int g = exgcd (b, a % b, x, y);
	int t = x;
	x = y;
	y = t - a / b * y;
	return g;
}
int check (string s) {
	int res = 0;
	for (int i = 0; i < s.size(); i++) {
		res = (res * 10 + (s[i] - '0')) % mod;
	}
	return res;
}
string s1, s2;
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> s1 >> s2;
	int a = check (s1);
	int b = check (s2);
	int x = 0, y = 0;
	int g = exgcd (b, mod, x, y);
	x = (x % mod + mod) % mod;
	cout << a * x % mod;
	return 0;
}
